args.sparql:
SELECT DISTINCT ?positionLabel WHERE {
  ?legislature wdt:P31/wdt:P279* wd:Q1758035 .  # Instance of legislative body
  ?position wdt:P361 ?legislature .           # Position part of legislature

  ?position rdfs:label ?positionLabel .
  FILTER(LANG(?positionLabel) = "en") .

  # Find current holders
  ?person p:P39 ?positionStatement .
  ?positionStatement ps:P39 ?position .
  FILTER NOT EXISTS {
    ?positionStatement pq:P582 ?endTime
  }
}

SELECT DISTINCT ?positionLabel WHERE {
  ?position wdt:P31/wdt:P279* wd:Q1758037 .  # Position is instance or subclass of legislative speaker

  ?person p:P39 ?positionStatement .
  ?positionStatement ps:P39 ?position .

  FILTER NOT EXISTS {
    ?positionStatement pq:P582 ?endTime .
  }

  ?position rdfs:label ?positionKey .
  FILTER(LANG(?positionKey) = "en") .
  BIND(STRLANG(CONCAT(?positionKey, " (title)"), "en") AS ?positionLabel)
}

SELECT DISTINCT ?positionLabel WHERE {
  ?position wdt:P31/wdt:P279* wd:Q1758037 .  # Position is instance or subclass of legislative speaker/president

  ?person p:P39 ?positionStatement .
  ?positionStatement ps:P39 ?position .

  FILTER NOT EXISTS {
    ?positionStatement pq:P582 ?endTime .
  }

  ?position rdfs:label ?positionKey .
  FILTER(LANG(?positionKey) = "en") .
  FILTER(CONTAINS(LCASE(?positionKey), "president"))

  BIND(STRLANG(CONCAT(?positionKey, " (title)"), "en") AS ?positionLabel)
}
